/** CmmtRoleDao.insert */
insert into cmmt_role (
	 role_id
	,role_nm
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{roleId}
	,#{roleNm}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtRoleDao.update */
update cmmt_role set
	role_nm = #{roleNm}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where role_id = #{roleId}

mapper.delete:
/** CmmtRoleDao.delete */
delete from cmmt_role
